package genxsolution.vms.vmsbackend.vehicle_management.vehicle_operating_cost.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_operating_cost.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_operating_cost.service.VehicleOperatingCostService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/operating-costs") public class VehicleOperatingCostController { private final VehicleOperatingCostService service; public VehicleOperatingCostController(VehicleOperatingCostService service){this.service=service;} @GetMapping public List<VehicleOperatingCostResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleOperatingCostResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleOperatingCostResponse create(@RequestBody VehicleOperatingCostUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleOperatingCostResponse update(@PathVariable UUID id,@RequestBody VehicleOperatingCostUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
